      rec.errorMessage =
        server.verify_error ??
        "Still confirming this check-in reached the server…";
      changed = true;
    } else if (rec.errorMessage) {
      // Recovered (e.g. a re-drive cleared the flag) — drop the stale message.
      rec.errorMessage = null;
      changed = true;
    }
