    synology_fallback_allowed: truthy(cfg["HELPER_SYNOLOGY_FALLBACK_ALLOWED"]),
    seafile_server_url: (cfg["HELPER_SEAFILE_SERVER_URL"] as string) ?? null,
    seafile_libraries: seafileLibraries,
  });
}

